package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvPensioenZorgSector;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;

public class BerekenBvVakantiegeld extends BerekenBvExceptioneel {

    public BerekenBvVakantiegeld(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        initFiscaleConstanten(rekenTijd);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY) && BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                berekenBvVakantiegeld(opdrachtContext, opdracht);
            }
        }
        BvPensioenZorgSector bvPensioenZorgSector = new BvPensioenZorgSector(RekenBvKey.BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY, taxdatum, constantManager);
        bvPensioenZorgSector.behandel(mainContext);
        return CONTINUE_PROCESSING;
    }

    private void berekenBvVakantiegeld(RekenContext opdrachtContext, Opdracht opdracht) {
        LoonElementManager manager = opdrachtContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        Money belastbaarVakantiegeld = getBelastbaar(BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY, BELASTBAAR_KEY, loonElementen);
        Money jaarInkomen = opdrachtContext.getMoney(BELASTBAAR_THEORETISCH_JAARWEDDE_KEY);
        Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
        Money bedrijfsvoorheffingVakantiegeld =
                berekenBVExceptioneel(opperLaatsteGegevens, jaarInkomen, belastbaarVakantiegeld, true, opdrachtContext);
        herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY, bedrijfsvoorheffingVakantiegeld, BELASTBAAR_KEY,
                belastbaarVakantiegeld, loonElementen);
    }

}
